import{_ as e,o as d,c as l,ag as o}from"./chunks/framework.BGkQCay2.js";const f=JSON.parse('{"title":"SIR Optimization Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/simd/sir-pipeline.md","filePath":"guide/simd/sir-pipeline.md"}'),a={name:"guide/simd/sir-pipeline.md"};function i(c,t,n,s,r,g){return d(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="sir-optimization-pipeline" tabindex="-1">SIR Optimization Pipeline <a class="header-anchor" href="#sir-optimization-pipeline" aria-label="Permalink to &quot;SIR Optimization Pipeline&quot;">​</a></h1><p>This page describes the current pipeline conservatively: what is clearly implemented, what route a workload tends to take, and where the sharp edges still are.</p><h2 id="high-level-picture" tabindex="-1">High-level picture <a class="header-anchor" href="#high-level-picture" aria-label="Permalink to &quot;High-level picture&quot;">​</a></h2><p>There are two different optimization routes that often get conflated:</p><ul><li>compiler-side inline SIMD for qualifying small static arrays</li><li>SIR lowering and backend dispatch for tensor or graph workloads</li></ul><p>Conceptually:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source code</span></span>\n<span class="line"><span>  -&gt; HIR</span></span>\n<span class="line"><span>  -&gt; either small-array inline SIMD</span></span>\n<span class="line"><span>  -&gt; or SIR graph lowering</span></span>\n<span class="line"><span>  -&gt; backend selection</span></span>\n<span class="line"><span>  -&gt; LLVM IR / target code</span></span></code></pre></div><h2 id="route-1-inline-simd-for-small-arrays" tabindex="-1">Route 1: inline SIMD for small arrays <a class="header-anchor" href="#route-1-inline-simd-for-small-arrays" aria-label="Permalink to &quot;Route 1: inline SIMD for small arrays&quot;">​</a></h2><p>The compiler has a dedicated <code>simd_small</code> path for qualifying fixed-size arrays.</p><p>The current backend threshold is explicit:</p><ul><li>maximum 64 bytes total</li><li>maximum 64 elements</li><li>element count must be a power of two</li></ul><p>That threshold is implemented in <code>crates/vex-sir/src/codegen/backends/simd/inline.rs</code> and mirrored by the small-array codegen helpers in <code>crates/vex-compiler/src/codegen_hir/expr/simd_small</code>.</p><p>Typical examples on this path are:</p><ul><li>element-wise arithmetic on <code>[T; N]</code></li><li>vector comparisons on <code>[T; N]</code></li><li>reductions such as <code>\\+</code> and <code>\\&gt;</code> on small arrays</li></ul><p>Example:</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sum8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">])</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>On this path, the likely evidence in emitted LLVM is:</p><ul><li><code>&lt;N x T&gt;</code> vector values</li><li><code>insertelement</code> chains for tiny literals</li><li><code>llvm.vector.reduce.*</code> intrinsics for reductions</li></ul><h2 id="route-2-sir-for-tensor-and-graph-code" tabindex="-1">Route 2: SIR for tensor and graph code <a class="header-anchor" href="#route-2-sir-for-tensor-and-graph-code" aria-label="Permalink to &quot;Route 2: SIR for tensor and graph code&quot;">​</a></h2><p>When code is written around <code>graph fn</code>, <code>Tensor&lt;T&gt;</code>, or other graph-shaped tensor operations, the compiler lowers into SIR first and then chooses a backend based on shapes and supported node families.</p><p>This route is the right mental model for:</p><ul><li>dynamic tensors</li><li>graph compute</li><li>gather and scatter families</li><li>backend dispatch between CPU SIMD and GPU-style paths</li></ul><h2 id="static-and-dynamic-shape-routing" tabindex="-1">Static and dynamic shape routing <a class="header-anchor" href="#static-and-dynamic-shape-routing" aria-label="Permalink to &quot;Static and dynamic shape routing&quot;">​</a></h2><p>The internal contract distinguishes between static and dynamic shapes:</p><ul><li>static tensors like <code>Tensor&lt;f32, 4&gt;</code> carry fixed shape information</li><li>dynamic tensors like <code>Tensor&lt;f32&gt;</code> lower to <code>%VexDynTensor { ptr, i64 }</code></li><li><code>Span&lt;T&gt;</code> lowers as a non-owning <code>%VexSlice { ptr, i64 }</code></li></ul><p>That distinction is not cosmetic. A dynamic tensor owns storage and participates in drop behavior, while a span is a borrowed view.</p><h2 id="important-coercion-boundary" tabindex="-1">Important coercion boundary <a class="header-anchor" href="#important-coercion-boundary" aria-label="Permalink to &quot;Important coercion boundary&quot;">​</a></h2><p>One of the easy mistakes is assuming every tensor-like value is interchangeable because the layouts look similar.</p><p>They are not.</p><p>The compiler has an explicit safety guard to avoid silently fabricating an owning dynamic tensor from a stack-aliased vector value. Conversions into <code>Tensor&lt;T&gt;</code> must go through the proper owned path.</p><p>In practical terms:</p><ul><li><code>Span&lt;T&gt; -&gt; Tensor&lt;T&gt;</code> should be treated as an owned conversion</li><li><code>Tensor&lt;T&gt;</code> and <code>Span&lt;T&gt;</code> are not just two names for the same thing</li><li>bugs at generic call boundaries have historically shown up exactly here</li></ul><h2 id="unified-silicon-ir-sir-operator-reference" tabindex="-1">Unified Silicon IR (SIR) Operator Reference <a class="header-anchor" href="#unified-silicon-ir-sir-operator-reference" aria-label="Permalink to &quot;Unified Silicon IR (SIR) Operator Reference&quot;">​</a></h2><p>All data-parallel operations in Vex graph and tensor pipelines lower to a standardized set of SIR operators, which are optimized across different backend architectures (CPU/SIMD, Metal, Vulkan, and WebGPU).</p><h3 id="binary-operators-binop" tabindex="-1">Binary Operators (<code>BinOp</code>) <a class="header-anchor" href="#binary-operators-binop" aria-label="Permalink to &quot;Binary Operators (`BinOp`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Operator Category</th><th style="text-align:left;">BinOp</th><th style="text-align:left;">Vex Syntax</th><th style="text-align:left;">LLVM Instruction / Intrinsic</th><th style="text-align:left;">Metal / CUDA / Vulkan</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Arithmetic</strong></td><td style="text-align:left;"><code>Add</code></td><td style="text-align:left;"><code>a + b</code></td><td style="text-align:left;"><code>fadd</code> / <code>add</code></td><td style="text-align:left;"><code>+</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Sub</code></td><td style="text-align:left;"><code>a - b</code></td><td style="text-align:left;"><code>fsub</code> / <code>sub</code></td><td style="text-align:left;"><code>-</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Mul</code></td><td style="text-align:left;"><code>a * b</code></td><td style="text-align:left;"><code>fmul</code> / <code>mul</code></td><td style="text-align:left;"><code>*</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Div</code></td><td style="text-align:left;"><code>a / b</code></td><td style="text-align:left;"><code>fdiv</code> / <code>sdiv</code></td><td style="text-align:left;"><code>/</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Mod</code></td><td style="text-align:left;"><code>a % b</code></td><td style="text-align:left;"><code>frem</code> / <code>srem</code></td><td style="text-align:left;"><code>fmod</code> / <code>%</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Pow</code></td><td style="text-align:left;"><code>a ** b</code></td><td style="text-align:left;"><code>llvm.pow.*</code></td><td style="text-align:left;"><code>pow</code> / <code>powf</code></td></tr><tr><td style="text-align:left;"><strong>Saturating</strong></td><td style="text-align:left;"><code>SaturatingAdd</code></td><td style="text-align:left;">`a +</td><td style="text-align:left;">b`</td><td style="text-align:left;">Clamped add</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>SaturatingSub</code></td><td style="text-align:left;">`a -</td><td style="text-align:left;">b`</td><td style="text-align:left;">Clamped sub</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>SaturatingMul</code></td><td style="text-align:left;">`a *</td><td style="text-align:left;">b`</td><td style="text-align:left;">Clamped mul</td></tr><tr><td style="text-align:left;"><strong>Comparison</strong></td><td style="text-align:left;"><code>Eq</code> / <code>Ne</code></td><td style="text-align:left;"><code>a == b</code> / <code>a != b</code></td><td style="text-align:left;"><code>icmp eq</code> / <code>fcmp oeq</code></td><td style="text-align:left;">Returns <code>Mask&lt;N&gt;</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Lt</code> / <code>Le</code></td><td style="text-align:left;"><code>a &lt; b</code> / <code>a &lt;= b</code></td><td style="text-align:left;"><code>icmp</code> / <code>fcmp</code></td><td style="text-align:left;">Returns <code>Mask&lt;N&gt;</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Gt</code> / <code>Ge</code></td><td style="text-align:left;"><code>a &gt; b</code> / <code>a &gt;= b</code></td><td style="text-align:left;"><code>icmp</code> / <code>fcmp</code></td><td style="text-align:left;">Returns <code>Mask&lt;N&gt;</code></td></tr><tr><td style="text-align:left;"><strong>Logical</strong></td><td style="text-align:left;"><code>And</code> / <code>Or</code></td><td style="text-align:left;"><code>a &amp;&amp; b</code> / <code>a || b</code></td><td style="text-align:left;"><code>and</code> / <code>or</code></td><td style="text-align:left;"><code>&amp;&amp;</code> / <code>||</code></td></tr><tr><td style="text-align:left;"><strong>Bitwise</strong></td><td style="text-align:left;"><code>BitAnd</code> / <code>BitOr</code></td><td style="text-align:left;"><code>a &amp; b</code> / <code>a | b</code></td><td style="text-align:left;"><code>and</code> / <code>or</code></td><td style="text-align:left;"><code>&amp;</code> / <code>|</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>BitXor</code></td><td style="text-align:left;"><code>a ^ b</code></td><td style="text-align:left;"><code>xor</code></td><td style="text-align:left;"><code>^</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Shl</code> / <code>Shr</code></td><td style="text-align:left;"><code>a &lt;&lt; b</code> / <code>a &gt;&gt; b</code></td><td style="text-align:left;"><code>shl</code> / <code>lshr</code> or <code>ashr</code></td><td style="text-align:left;"><code>&lt;&lt;</code> / <code>&gt;&gt;</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>RotL</code> / <code>RotR</code></td><td style="text-align:left;"><code>a &lt;&lt;&lt; b</code> / <code>a &gt;&gt;&gt; b</code></td><td style="text-align:left;"><code>llvm.fshl</code> / <code>llvm.fshr</code></td><td style="text-align:left;"><code>rotate</code> (Metal/CUDA)</td></tr><tr><td style="text-align:left;"><strong>Min/Max</strong></td><td style="text-align:left;"><code>Min</code> / <code>Max</code></td><td style="text-align:left;"><code>a &lt;? b</code> / <code>a &gt;? b</code></td><td style="text-align:left;"><code>llvm.minnum</code> / <code>llvm.maxnum</code></td><td style="text-align:left;"><code>min</code> / <code>max</code></td></tr><tr><td style="text-align:left;"><strong>Matrix/Vector</strong></td><td style="text-align:left;"><code>MatMul</code></td><td style="text-align:left;"><code>a &lt;*&gt; b</code></td><td style="text-align:left;">Lowered to MatMul Node</td><td style="text-align:left;">Blas / Metal kernel</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>MatPow</code></td><td style="text-align:left;"><code>a &lt;^&gt; n</code></td><td style="text-align:left;">Matrix Exponentiation</td><td style="text-align:left;">Iterative / Spectral</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Dot</code> / <code>Cross</code></td><td style="text-align:left;"><code>a · b</code> / <code>a × b</code></td><td style="text-align:left;">Vector Dot / Cross</td><td style="text-align:left;"><code>dot</code> / <code>cross</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Solve</code></td><td style="text-align:left;"><code>A &lt;\\&gt; b</code></td><td style="text-align:left;">Lowered to Solve Node</td><td style="text-align:left;">Linear Solver (Ax=b)</td></tr><tr><td style="text-align:left;"><strong>Extended Math</strong></td><td style="text-align:left;"><code>Atan2</code> / <code>Hypot</code></td><td style="text-align:left;"><code>atan2(y,x)</code> / <code>hypot(x,y)</code></td><td style="text-align:left;"><code>atan2</code> / <code>llvm.sqrt</code></td><td style="text-align:left;"><code>atan2</code> / <code>hypot</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Fmod</code> / <code>Copysign</code></td><td style="text-align:left;"><code>fmod(x,y)</code> / <code>copysign(x,y)</code></td><td style="text-align:left;"><code>frem</code> / <code>llvm.copysign</code></td><td style="text-align:left;"><code>fmod</code> / <code>copysign</code></td></tr><tr><td style="text-align:left;"><strong>Special</strong></td><td style="text-align:left;"><code>GaloisMul</code></td><td style="text-align:left;"><code>a *^ b</code></td><td style="text-align:left;">Carry-less multiply</td><td style="text-align:left;"><code>pmul</code> (AVX) / clmul</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Concat</code></td><td style="text-align:left;"><code>a ++ b</code></td><td style="text-align:left;">Lowered to Concat Node</td><td style="text-align:left;">Dynamic Concatenation</td></tr></tbody></table><hr><h3 id="unary-operators-unaryop" tabindex="-1">Unary Operators (<code>UnaryOp</code>) <a class="header-anchor" href="#unary-operators-unaryop" aria-label="Permalink to &quot;Unary Operators (`UnaryOp`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Operator Category</th><th style="text-align:left;">UnaryOp</th><th style="text-align:left;">Vex Syntax</th><th style="text-align:left;">LLVM / Backend Mapping</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Basic</strong></td><td style="text-align:left;"><code>Neg</code> / <code>Not</code></td><td style="text-align:left;"><code>-x</code> / <code>!x</code></td><td style="text-align:left;"><code>fneg</code> or <code>sub 0, x</code> / <code>xor x, true</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>BitNot</code></td><td style="text-align:left;"><code>~x</code></td><td style="text-align:left;"><code>xor x, -1</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Cast</code></td><td style="text-align:left;"><code>x as T</code></td><td style="text-align:left;"><code>trunc</code> / <code>ext</code> / <code>fptosi</code> / <code>sitofp</code></td></tr><tr><td style="text-align:left;"><strong>Math Functions</strong></td><td style="text-align:left;"><code>Abs</code> / <code>Sqrt</code></td><td style="text-align:left;"><code>abs(x)</code> / <code>sqrt(x)</code></td><td style="text-align:left;"><code>llvm.fabs.*</code> / <code>llvm.sqrt.*</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Exp</code> / <code>Exp2</code></td><td style="text-align:left;"><code>exp(x)</code> / <code>exp2(x)</code></td><td style="text-align:left;"><code>llvm.exp.*</code> / <code>llvm.exp2.*</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Log</code> / <code>Log2</code> / <code>Log10</code></td><td style="text-align:left;"><code>log(x)</code> / <code>log2</code> / <code>log10</code></td><td style="text-align:left;"><code>llvm.log.*</code> / <code>llvm.log2.*</code> / <code>llvm.log10.*</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Sin</code> / <code>Cos</code> / <code>Tan</code></td><td style="text-align:left;"><code>sin(x)</code> / <code>cos</code> / <code>tan</code></td><td style="text-align:left;"><code>llvm.sin.*</code> / <code>llvm.cos.*</code> / <code>tan</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Floor</code> / <code>Ceil</code> / <code>Round</code></td><td style="text-align:left;"><code>floor</code> / <code>ceil</code> / <code>round</code></td><td style="text-align:left;"><code>llvm.floor.*</code> / <code>llvm.ceil.*</code> / <code>llvm.round.*</code></td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Trunc</code> / <code>Rint</code></td><td style="text-align:left;"><code>trunc(x)</code> / <code>rint(x)</code></td><td style="text-align:left;"><code>llvm.trunc.*</code> / <code>llvm.rint.*</code> (Banker&#39;s round)</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Rsqrt</code></td><td style="text-align:left;"><code>rsqrt(x)</code></td><td style="text-align:left;"><code>1.0 / llvm.sqrt.*</code></td></tr><tr><td style="text-align:left;"><strong>Activation</strong></td><td style="text-align:left;"><code>Relu</code></td><td style="text-align:left;"><code>relu(x)</code></td><td style="text-align:left;"><code>max(0, x)</code> (fused element-wise)</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Sigmoid</code></td><td style="text-align:left;"><code>sigmoid(x)</code></td><td style="text-align:left;"><code>1.0 / (1.0 + exp(-x))</code></td></tr><tr><td style="text-align:left;"><strong>Matrix</strong></td><td style="text-align:left;"><code>Transpose</code></td><td style="text-align:left;"><code>a^T</code> or <code>a.T</code></td><td style="text-align:left;">Lowered to Permute Node</td></tr></tbody></table><hr><h3 id="ternary-operators-ternaryop" tabindex="-1">Ternary Operators (<code>TernaryOp</code>) <a class="header-anchor" href="#ternary-operators-ternaryop" aria-label="Permalink to &quot;Ternary Operators (`TernaryOp`)&quot;">​</a></h3><ul><li><strong><code>Fma</code></strong>: Fused Multiply-Add (<code>a * b + c</code>). Lowers directly to hardware <code>llvm.fma.*</code> or GPU FMA instructions.</li><li><strong><code>Clamp</code></strong>: Value clamping (<code>clamp(val, min, max)</code>). Lowers to nested min/max intrinsics.</li><li><strong><code>Select</code></strong>: Conditional selection (<code>cond ? true_val : false_val</code>). Lowers to LLVM <code>select</code> instruction.</li></ul><hr><h3 id="reduction-operators-reduceop" tabindex="-1">Reduction Operators (<code>ReduceOp</code>) <a class="header-anchor" href="#reduction-operators-reduceop" aria-label="Permalink to &quot;Reduction Operators (`ReduceOp`)&quot;">​</a></h3><p>Reduction operations accumulate tensor elements along specified axes:</p><ul><li><strong><code>Sum</code> (<code>&lt;+ arr</code>)</strong>: Computes the sum of elements (LLVM <code>llvm.vector.reduce.fadd</code>).</li><li><strong><code>Prod</code> (<code>&lt;* arr</code>)</strong>: Computes the product of elements (LLVM <code>llvm.vector.reduce.fmul</code>).</li><li><strong><code>Min</code> (<code>&lt;?| arr</code>) / <code>Max</code> (<code>&gt;?| arr</code>)</strong>: Computes minimum/maximum elements (LLVM <code>llvm.vector.reduce.fmin</code> / <code>fmax</code>).</li><li><strong><code>And</code> (<code>&lt;&amp; arr</code>) / <code>Or</code> (<code>&lt;\\| arr</code>)</strong>: Logical/bitwise reductions on masks.</li><li><strong><code>Mean</code></strong>: Computed as <code>Sum / N</code>.</li><li><strong><code>ArgMin</code> / <code>ArgMax</code></strong>: Computes the index of the minimum/maximum element.</li></ul><hr><h3 id="mask-operators-maskop" tabindex="-1">Mask Operators (<code>MaskOp</code>) <a class="header-anchor" href="#mask-operators-maskop" aria-label="Permalink to &quot;Mask Operators (`MaskOp`)&quot;">​</a></h3><p>These operate on boolean <code>Mask&lt;N&gt;</code> vectors and return scalar results:</p><ul><li><strong><code>ToBitmask</code></strong>: Converts a <code>Mask&lt;N&gt;</code> to an integer bitmask (<code>iN</code>) representing lanes (LLVM <code>bitcast &lt;N x i1&gt; -&gt; iN</code>).</li><li><strong><code>FromBitmask</code></strong>: Converts an integer bitmask to a <code>Mask&lt;N&gt;</code>.</li><li><strong><code>Any</code> / <code>All</code></strong>: Returns <code>true</code> if any/all lanes are true (<code>icmp ne bitmask, 0</code> / <code>icmp eq bitmask, all_ones</code>).</li><li><strong><code>CountSetBits</code></strong>: Returns the count of true lanes (LLVM <code>llvm.ctpop</code>).</li><li><strong><code>FirstSet</code></strong>: Returns the index of the first true lane, or <code>-1</code> if none (LLVM <code>llvm.cttz</code>).</li><li><strong><code>MaskAnd</code> / <code>MaskOr</code> / <code>MaskXor</code> / <code>MaskNot</code></strong>: Logical bitwise operations on masks.</li></ul><hr><h2 id="backend-operator-support-matrix" tabindex="-1">Backend Operator Support Matrix <a class="header-anchor" href="#backend-operator-support-matrix" aria-label="Permalink to &quot;Backend Operator Support Matrix&quot;">​</a></h2><p>The following table summarizes compiler code generation support for Silicon IR (SIR) operations across backends:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Operator Category</th><th style="text-align:left;">CPU (SIMD/Scalar)</th><th style="text-align:left;">macOS (Metal)</th><th style="text-align:left;">Linux/Windows (Vulkan)</th><th style="text-align:left;">Web (WebGPU/WGSL)</th><th style="text-align:left;">CUDA / ROCm</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Element-wise Math</strong></td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td></tr><tr><td style="text-align:left;"><strong>Reductions</strong></td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td><td style="text-align:left;">✅ Full</td></tr><tr><td style="text-align:left;"><strong>Mask Ops</strong></td><td style="text-align:left;">✅ Native (cttz/ctpop)</td><td style="text-align:left;">✅ Native (<code>popcount</code>)</td><td style="text-align:left;">✅ Native (subgroup)</td><td style="text-align:left;">✅ Native</td><td style="text-align:left;">✅ Native</td></tr><tr><td style="text-align:left;"><strong>Matrix Operations</strong></td><td style="text-align:left;">✅ LLVM-SIMD / BLAS</td><td style="text-align:left;">✅ Metal Kernels</td><td style="text-align:left;">✅ SPIR-V MatMul</td><td style="text-align:left;">✅ WGSL Compute</td><td style="text-align:left;">✅ CuBLAS / HIP</td></tr><tr><td style="text-align:left;"><strong>Saturating Arithmetic</strong></td><td style="text-align:left;">✅ Native</td><td style="text-align:left;">✅ Clamped emulation</td><td style="text-align:left;">✅ Clamped emulation</td><td style="text-align:left;">✅ Clamped</td><td style="text-align:left;">✅ Native</td></tr><tr><td style="text-align:left;"><strong>Quantized/Sparse</strong></td><td style="text-align:left;">✅ SIMD-optimized</td><td style="text-align:left;">✅ MSL Quantized</td><td style="text-align:left;">🟡 Partial</td><td style="text-align:left;">🟡 Partial</td><td style="text-align:left;">✅ CUDA Kernels</td></tr></tbody></table><hr><h2 id="performance-routing-flop-weights" tabindex="-1">Performance Routing &amp; FLOP Weights <a class="header-anchor" href="#performance-routing-flop-weights" aria-label="Permalink to &quot;Performance Routing &amp; FLOP Weights&quot;">​</a></h2><p>When evaluating whether to dispatch a tensor workload to the CPU or GPU at runtime, Vex uses a complexity cost model based on operator FLOP weights:</p><ul><li><strong>Weight 1.0 (Trivial)</strong>: <code>Abs</code>, <code>Neg</code>, <code>Floor</code>, <code>Ceil</code>, <code>Round</code>, <code>Trunc</code>, <code>Rint</code>, <code>Sign</code>, <code>Not</code>, <code>BitNot</code>, <code>Relu</code>.</li><li><strong>Weight 2.0 (Basic Math)</strong>: <code>Fmod</code>, <code>Copysign</code>.</li><li><strong>Weight 4.0 (Hardware-optimized)</strong>: <code>Sqrt</code>, <code>Rsqrt</code>, <code>Cbrt</code>.</li><li><strong>Weight 6.0 (Composite)</strong>: <code>Hypot</code>.</li><li><strong>Weight 8.0 (Transcendental)</strong>: <code>Sin</code>, <code>Cos</code>, <code>Tan</code>, <code>Exp</code>, <code>Log</code>, <code>Exp2</code>, <code>Expm1</code>, <code>Log2</code>, <code>Log10</code>, <code>Log1p</code>, <code>Sinh</code>, <code>Cosh</code>, <code>Tanh</code>.</li><li><strong>Weight 10.0 (Inverse Trig / Activation)</strong>: <code>Asin</code>, <code>Acos</code>, <code>Atan</code>, <code>Asinh</code>, <code>Acosh</code>, <code>Atanh</code>, <code>Atan2</code>, <code>Sigmoid</code>, <code>Erf</code>.</li><li><strong>Weight 12.0 (Exponentiation)</strong>: <code>Pow</code>.</li></ul><p>Workloads with cumulative FLOP scores exceeding the dispatch threshold are automatically offloaded to the target GPU backend (e.g. Metal).</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./index">SIMD and Auto-Vectorization</a></li><li><a href="./tensor-mask">Tensor and Mask Types</a></li><li><a href="/docs/guide/gpu">GPU Programming</a></li></ul>',62)])])}const x=e(a,[["render",i]]);export{f as __pageData,x as default};
